# Pseudocode: decide which model to use
if task == "fast_classification_or_extraction":
    model_name = "gemini-2.0-flash"  # 10x cheaper, sub-second latency
elif task == "reasoning_or_math":
    model_name = "gemini-2.0-flash-thinking"  # Explicit chain-of-thought
elif context_tokens > 500000 or task == "long_document_analysis":
    model_name = "gemini-1.5-pro"  # 2M token context
elif budget_critical and quality_sufficient:
    model_name = "gemini-1.5-flash-8b"  # Cheapest option
else:
    model_name = "gemini-2.0-flash"  # Default fallback

import json

model = genai.GenerativeModel(
    model_name="gemini-1.5-pro",
    generation_config={
        "response_mime_type": "application/json",
        "response_schema": {
            "type": "object",
            "properties": {
                "name": {"type": "string"},
                "price": {"type": "number"},
                "features": {"type": "array", "items": {"type": "string"}}
            },
            "required": ["name", "price"]
        }
    }
)

response = model.generate_content("Create a product listing for wireless earbuds")
product = json.loads(response.text)
print(f"Name: {product['name']}, Price: {product['price']}")

model = genai.GenerativeModel("gemini-2.0-flash")
response = model.generate_content( "Write a long story about space exploration", stream=True )
for chunk in response: print(chunk.text, end="", flush=True)

model = genai.GenerativeModel("gemini-1.5-pro") chat = model.start_chat()
response = chat.send_message("Tell me about Mars", stream=True)
for chunk in response: print(chunk.text, end="")

from google.generativeai.types import HarmCategory, HarmBlockThreshold

model = genai.GenerativeModel(
    model_name="gemini-1.5-pro",
    safety_settings={
        HarmCategory.HARM_CATEGORY_HARASSMENT: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
        HarmCategory.HARM_CATEGORY_HATE_SPEECH: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
        HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
        HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
    }
)

response = model.generate_content("Your prompt")

# Check block before accessing text
if response.prompt_feedback.block_reason:
    print(f"Prompt blocked: {response.prompt_feedback.block_reason}")
else:
    print(response.text)
    for rating in response.candidates[0].safety_ratings:
        print(f"{rating.category}: {rating.probability}")

from google.generativeai.types import StopCandidateException, BlockedPromptException

try:
    response = model.generate_content("Your prompt")
    print(response.text)

except BlockedPromptException as e:
    print(f"Prompt blocked: {e}")

except StopCandidateException as e:
    print(f"Generation stopped: {e}")
    # Partial response may be available
    if e.args and e.args[0].content:
        print(f"Partial: {e.args[0].content.parts[0].text}")

except Exception as e:
    print(f"Unexpected error: {e}")

import time
from google.api_core.exceptions import ResourceExhausted

def generate_with_retry(prompt, max_retries=3):
    for attempt in range(max_retries):
        try:
            return model.generate_content(prompt)
        except ResourceExhausted:
            if attempt < max_retries - 1:
                wait_time = 2 ** attempt  # 1s, 2s, 4s
                print(f"Rate limited, waiting {wait_time}s...")
                time.sleep(wait_time)
            else:
                raise

# Cost-optimized: Flash + explicit output limit
model = genai.GenerativeModel(
    model_name="gemini-2.0-flash",  # 10x cheaper than Pro
    generation_config={
        "max_output_tokens": 1024,   # Explicit limit
        "temperature": 0.7,
    }
)

response = model.generate_content("Classify this customer message")
